var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"POOR_NPC_NULL_BOSS","text":{"KOREA":"크윽…?! 뭐가 이렇게 강해?!","JPN":"くっ……！？　なんて強いんだ！？","ENG":"Krrgh...?! How're you so strong?!","TWN":"唔…？怎麼這麼厲害？！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그대… 짐승의 것이 아닌 피냄새가 짙게 나는구려.","JPN":"貴殿……獣のものではない濃い血の匂いがします。","ENG":"You... reek of blood that is not of a beast.","TWN":"你…身上的不是野獸的氣味，而是濃濃的血腥味。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그라운드 원은 평화로운 도시라 들었소만, 이런 곳에서도 그토록 많은 살생이 필요한 거요?","JPN":"グラウンド・ワンは平和な街だと聞いていますが、このようなところでも多くの殺傷が必要なのですか？","ENG":"I heard Ground One was a peaceful city. How is it that so much bloodshed is needed here?","TWN":"在下聽說G1是一個和平的都市，結果也需要這麼多的殺戮嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"POOR_NPC_NULL_BOSS","text":{"KOREA":"뭐…?","JPN":"何だと……？","ENG":"What...?","TWN":"什麼…？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"POOR_NPC_NULL_BOSS","text":{"KOREA":"하, 웃기는군. 살인마 집단의 수장이 그런 입바른 소릴 하다니.","JPN":"は、笑わせてくれるな。殺人鬼の頭がそんなごもっともな話をするとは。","ENG":"Hah, that's funny coming from the leader of a group of assassins.","TWN":"哈，真可笑，自己身為殺人魔集團的幫主，卻說出這種冠冕堂皇的話。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"본인을 알고 있소?","JPN":"自分を知っているのですか？","ENG":"You know who I am?","TWN":"你認識在下嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"POOR_NPC_NULL_BOSS","text":{"KOREA":"그래. 널 만나고 싶어하는 사람에게 들었지. 숨만 붙어있으면 상태는 아무래도 상관없다더군.","JPN":"ああ。お前に会いたがってる人から聞いたんだ。生きてさえいれば、状態はどうでもいいらしい。","ENG":"Yeah. I know someone who wants to meet you. He said he doesn't care what state you're in. Just as long as you're still breathing.","TWN":"對，有人想見你，而且人怎麼樣都無所謂，只要是活口就好。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"POOR_NPC_NULL_BOSS","text":{"KOREA":"그러니, 적당히 힘 조절은 해 주마!","JPN":"だから、適当に手加減はしてやる！","ENG":"So, let me put you in line!","TWN":"所以，我會控制一下力道的！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L15_1","type":"dialog","speaker":"POOR_NPC_NULL_B","text":{"KOREA":"두… 두목님이 엘릭서를 쓰셨어! 평소엔 돈 아깝다면서 한 방울도 쓰지 않았는데!","JPN":"あ……親分がエリクサーを飲んだ！　普段は金がもったいないからって一滴も使わないのに！","ENG":"B-boss just used the Elixir! He normally says it's a waste of money and doesn't even use a single drop of it!","TWN":"老大…用了聖水！平常他連一滴都不捨得用！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"POOR_NPC_NULL_A","text":{"KOREA":"저 여자는 이제 큰일났군.","JPN":"あの女、終わったな。","ENG":"This girl's good as dead now.","TWN":"那個女人現在麻煩大了。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그러고보니… 과거, 만무제에서 규칙을 어기고 약물을 썼다가 문파에서 추방당한 천재에 대해 들은 적이 있소.","JPN":"そういえば……過去に、万武祭で規則を破り薬物を使ったため、破門された天才のことを耳にしたことがあります。","ENG":"Come to think of it... I recall a story of a genius who was expelled from their sect for violating the rules and using drugs in the Great Martial Arts Tournament.","TWN":"在下聽說過…傳言有一個天才，因為在武林大會中違規使用禁藥而被逐出門派。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그자가 이곳 그라운드 원 변방에 자릴 잡고 있다던데…","JPN":"その者がこのグラウンド・ワンの辺境に住み着いているらしいですが……","ENG":"Last I heard, he was residing on the outskirts of Ground One...","TWN":"後來似乎就是在G1的偏遠地區找到立身之處…"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"혹시 그대가 그 파문인이오?","JPN":"もしや、貴殿がその追放者ですか？","ENG":"Are you him?","TWN":"難道那個人就是你？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"POOR_NPC_NULL_BOSS","text":{"KOREA":"흥, 만무제니 파문인이니 그딴 건 모르겠고…","JPN":"ふん、万武祭とか追放者とか、そんなのは知らんが……","ENG":"Pfft. I dunno anything about outcasts or tournaments...","TWN":"哼，我才不知道什麼武林大會跟那個傳言…"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"POOR_NPC_NULL_BOSS","text":{"KOREA":"우선 네놈의 건방진 콧대부터 꺾어주마!","JPN":"まずは生意気なてめえの鼻をへし折ってやる！","ENG":"All I care about right now is teaching you a lesson!","TWN":"我現在要先滅你的威風！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};